import{_ as s,o as i,c as t,ak as n}from"./chunks/framework.d_5_XLDx.js";const k=JSON.parse('{"title":"wsl将ubuntu换成debian","description":"","frontmatter":{"title":"wsl将ubuntu换成debian","createTime":"2025/01/26 20:18:30","permalink":"/article/ubm5k5vn/","tags":["wsl","debian","ubuntu","windows","linux","wsl2","windows10","windows11","windows-terminal"]},"headers":[],"relativePath":"blog/ermao/文档/wsl将ubuntu换成debian.md","filePath":"blog/ermao/文档/wsl将ubuntu换成debian.md","lastUpdated":1769775157000}'),e={name:"blog/ermao/文档/wsl将ubuntu换成debian.md"};function p(l,a,h,u,d,r){return i(),t("div",null,[...a[0]||(a[0]=[n(`<p>因为 debian 更稳定、更轻量，所以想把 wsl2 中的 ubuntu 换成 debian。</p><p>本文记录一下过程。</p><h2 id="步骤-1-导出当前的-ubuntu-发行版" tabindex="-1">步骤 1: 导出当前的 Ubuntu 发行版 <a class="header-anchor" href="#步骤-1-导出当前的-ubuntu-发行版" aria-label="Permalink to &quot;步骤 1: 导出当前的 Ubuntu 发行版&quot;">​</a></h2><p>首先，需要将当前的 Ubuntu 发行版导出为一个 <code>.tar</code> 文件，以便以后可以恢复（如果需要的话）。</p><p><strong>以下命令都是在 Windows PowerShell 中运行的。</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 确认当前的 Ubuntu 发行版名称</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wsl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --running</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 导出当前的 Ubuntu 发行版</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wsl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --export</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Ubuntu-20.04</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ubuntu_backup.tar</span></span></code></pre></div><p>这会将 Ubuntu 发行版导出到当前目录，并保存为 <code>ubuntu_backup.tar</code>。</p><p><img src="https://image.ermao.net/images/article/ubm5k5vn/image.png" alt="导出当前的 Ubuntu 发行版"></p><p>上面命令中的 <code>Ubuntu-20.04</code> 可能会因为你的 Ubuntu 版本而有所不同。确保将其替换为你的 Ubuntu 发行版名称。</p><h2 id="步骤-2-卸载当前的-ubuntu-发行版" tabindex="-1">步骤 2: 卸载当前的 Ubuntu 发行版 <a class="header-anchor" href="#步骤-2-卸载当前的-ubuntu-发行版" aria-label="Permalink to &quot;步骤 2: 卸载当前的 Ubuntu 发行版&quot;">​</a></h2><p>接下来，卸载 Ubuntu 发行版：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wsl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --unregister</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Ubuntu-20.04</span></span></code></pre></div><p><img src="https://image.ermao.net/images/article/ubm5k5vn/image-1.png" alt="卸载ubuntu"></p><p>这将删除现有的 Ubuntu 发行版，但不会影响导出的备份文件。</p><h2 id="步骤-3-安装-debian-发行版" tabindex="-1">步骤 3: 安装 Debian 发行版 <a class="header-anchor" href="#步骤-3-安装-debian-发行版" aria-label="Permalink to &quot;步骤 3: 安装 Debian 发行版&quot;">​</a></h2><p>可以从 Microsoft Store 安装 Debian。如果你喜欢命令行安装，可以使用以下命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wsl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Debian</span></span></code></pre></div><p><img src="https://image.ermao.net/images/article/ubm5k5vn/image-2.png" alt="安装 Debian 发行版"></p><p>这会自动安装最新版本的 Debian 发行版。首次运行时，Debian 会要求你创建一个新的用户和密码。</p><h2 id="步骤-4-恢复原来的数据-如果需要" tabindex="-1">步骤 4: 恢复原来的数据（如果需要） <a class="header-anchor" href="#步骤-4-恢复原来的数据-如果需要" aria-label="Permalink to &quot;步骤 4: 恢复原来的数据（如果需要）&quot;">​</a></h2><p>如果你想恢复 Ubuntu 发行版中的数据（比如在 Ubuntu 中安装的包或配置文件），可以将 <code>ubuntu_backup.tar</code> 文件导入到 Debian 中：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wsl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Debian-Backup</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">新安装路</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">径</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ubuntu_backup.tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span></code></pre></div><p>这将恢复你导出的 Ubuntu 数据到 Debian 发行版中。</p><h2 id="步骤-5-进入-debian" tabindex="-1">步骤 5: 进入 Debian <a class="header-anchor" href="#步骤-5-进入-debian" aria-label="Permalink to &quot;步骤 5: 进入 Debian&quot;">​</a></h2><p>通过以下命令进入新的 Debian 环境：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wsl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Debian</span></span></code></pre></div><p>完成这些步骤后，你就成功地将 WSL2 环境中的 Ubuntu 更换为 Debian。</p><p>如果之前用的 WindowsTerminal，记得改一下默认启动项。</p><p><img src="https://image.ermao.net/images/article/ubm5k5vn/image-3.png" alt="修改windowsterminal默认启动项"></p>`,29)])])}const o=s(e,[["render",p]]);export{k as __pageData,o as default};
